function FavouritesList(props) {
    return(

        <div>
            <h3>My Favourite Movies</h3>
            <ul>
                {
                    props.favourates.map(movie => (
                        <FavouriteMovie movie = {movie} />
                                        ))
                }
            </ul>
        </div>
    )
}
